CREATE TABLE series (
  serie_id                            TEXT                 PRIMARY KEY,
  series_number                       INTEGER             ,
  show_code                           TEXT                ,
  title                               TEXT                ,
  description                         TEXT                ,
  network                             TEXT                ,
  premiere_date                       TIMESTAMPTZ         ,
  finale_date                         TIMESTAMPTZ         
);
COMMENT ON TABLE series IS 'Table: Series';

CREATE TABLE seasons (
  season_id                           TEXT                 PRIMARY KEY,
  series                              TEXT                ,
  season_number                       INTEGER             ,
  title                               TEXT                ,
  description                         TEXT                ,
  start_airdate                       TIMESTAMPTZ         ,
  end_airdate                         TIMESTAMPTZ         ,
  mock_data_notes                     TEXT                
);
COMMENT ON TABLE seasons IS 'Table: Seasons';

CREATE TABLE episodes (
  episode_id                          TEXT                 PRIMARY KEY,
  season                              TEXT                ,
  episode_number                      INTEGER             ,
  description                         TEXT                ,
  airdate                             TIMESTAMPTZ         ,
  writers                             TEXT                ,
  director                            TEXT                ,
  runtime_minutes                     INTEGER             ,
  ratings                             TEXT                ,
  one_sentence_summary                TEXT                ,
  favorite_color                      TEXT                
);
COMMENT ON TABLE episodes IS 'Table: Episodes';

CREATE TABLE ratings (
  rating_id                           TEXT                 PRIMARY KEY,
  rating                              INTEGER             ,
  series                              TEXT                ,
  episode                             TEXT                ,
  users_name                          TEXT                ,
  email_address                       TEXT                ,
  phone_nmber                         TEXT                ,
  notes                               TEXT                ,
  created_at                          TIMESTAMPTZ         
);
COMMENT ON TABLE ratings IS 'Table: Ratings';

CREATE TABLE erb_versions (
  erb_version_id                      TEXT                 PRIMARY KEY,
